import React from 'react';
import Card from '@mui/material/Card';
import CardHeader from '@mui/material/CardHeader';
import CardContent from '@mui/material/CardContent';
import CardActions from '@mui/material/CardActions';
import FAWTypography from './FAWTypography';
import FAWButton from './FAWButton';
import AddIcon from '@mui/icons-material/Add';
import FAWInput from './FAWInput';
import FAWTextarea from './FAWTextarea';
import { colors } from "../../utils/designTokens";
// ...import other Atlas components as needed

const TYPE_MAP = {
  typography: FAWTypography,
  button: FAWButton,
  h1: 'h1',
  h2: 'h2',
  h3: 'h3',
  div: 'div',
  span: 'span',
  plusIcon: AddIcon,
  textfield: FAWInput,
  textarea: FAWTextarea,
  // ...add more mappings as needed
};

const renderByType = (item, idx) => {
  if (!item || !item.type) return null;
  const Comp = TYPE_MAP[item.type] || item.type;
  return <Comp key={item.key || idx} {...item.props}>{item.props?.children}</Comp>;
};

const FAWCard = ({ title, actions, content, children, sx, ...rest }) => (
  <Card sx={sx} {...rest}>
    {title && <CardHeader title={title} />}
    <CardContent>
      {Array.isArray(content)
        ? content.map(renderByType)
        : (content || children)}
    </CardContent>
    {actions && <CardActions>{actions}</CardActions>}
  </Card>
);

export default FAWCard; 